class AuditService {
    private final AuditRepository auditRepo;

    AuditService(AuditRepository auditRepo) {
        this.auditRepo = auditRepo;
    }

    @org.springframework.transaction.annotation.Transactional(propagation = org.springframework.transaction.annotation.Propagation.REQUIRES_NEW)
    public void saveAudit(String message) {
        auditRepo.save(new AuditLog(message));
    }
}

class OrderService {
    private final OrderRepository orderRepo;
    private final AuditService auditService;

    OrderService(OrderRepository orderRepo, AuditService auditService) {
        this.orderRepo = orderRepo;
        this.auditService = auditService;
    }

    @org.springframework.transaction.annotation.Transactional
    public void createOrder() {
        orderRepo.save(new Order("CREATED"));
        try {
            auditService.saveAudit("order created");
        } catch (RuntimeException ignored) {
            // audit izolasyonu
        }
    }
}

